#include <stdio.h>
#include <stdlib.h>

int main() {
    int n, m, p;
    scanf("%d %d %d", &n, &m, &p);
    int** matrix = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        matrix[i] = (int*)malloc(m * sizeof(int));
        for (int j = 0; j < m; j++) {
            matrix[i][j] = j + 1;
        }
    }
    for (int i = 0; i < p; i++) {
        int x, y;
        scanf("%d %d", &x, &y);
        matrix[x - 1][y - 1]++;
    }
    for (int i = 0; i < n; i++) {
        int cost = 0;
        for (int j = m - 1; j > 0; j--) {
            if (matrix[i][j - 1] > matrix[i][j]) {
                printf("-1\n");
                break;
            }
            cost += matrix[i][j] - matrix[i][j - 1];
            if (j == 1) {
                printf("%d\n", cost);
            }
        }
    }
    return 0;
}

